    try {
      const res = await fetch(`${API_URL}/admin/settings/maintenance`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json', 'Authorization': `Bearer ${token}` },
        body: JSON.stringify({ isMaintenance: newStatus })
      });
      if (res.ok) {
        setIsMaintenanceMode(newStatus);
        showNotification("Berjaya", newStatus ? "Maintenance Mode diaktifkan!" : "Maintenance Mode ditutup.", "success");
      } else {
        showNotification("Ralat", "Gagal menyimpan tetapan. Pastikan backend diupdate.", "error");
      }
    } catch (err) {
      showNotification("Ralat", "Masalah sambungan pelayan.", "error");
    }
  };

  const timeSince = (dateString) => {
    if(!dateString) return 'Belum Login';
    const seconds = Math.floor((new Date() - new Date(dateString)) / 1000);
    let interval = seconds / 31536000;
    if (interval > 1) return Math.floor(interval) + " tahun lepas";
    interval = seconds / 2592000;
    if (interval > 1) return Math.floor(interval) + " bulan lepas";
    interval = seconds / 86400;
    if (interval > 1) return Math.floor(interval) + " hari lepas";
    interval = seconds / 3600;
    if (interval > 1) return Math.floor(interval) + " jam lepas";
    interval = seconds / 60;
    if (interval > 1) return Math.floor(interval) + " minit lepas";
    return "Baru sahaja";
  };

