                       </div>
                       <Settings className="absolute -right-10 -top-10 opacity-10 text-white scale-150 rotate-45" size={200} />
                    </div>

                    <div className="p-6 sm:p-10 space-y-10">
                        {/* MAINTENANCE MODE SECTION */}
                        <section>
                            <h4 className="text-[10px] font-black text-amber-500 uppercase tracking-widest mb-4">Core System Controls</h4>
                            <div className="bg-amber-50 p-6 sm:p-8 rounded-3xl border border-amber-200 shadow-sm">
                                <div className="flex flex-col sm:flex-row items-start sm:items-center justify-between gap-6">
                                    <div className="flex items-start gap-4">
                                      <div className={`w-12 h-12 rounded-2xl flex items-center justify-center flex-shrink-0 ${isMaintenanceMode ? 'bg-amber-500 text-white' : 'bg-amber-200 text-amber-700'}`}>
                                        <Wrench size={24}/>
                                      </div>
                                      <div>
                                        <h3 className="text-lg font-black text-amber-900">Maintenance Mode</h3>
                                        <p className="text-sm font-medium text-amber-700 mt-1 max-w-sm">Tutup akses pelanggan (Portal & Login) sementara anda sedang mengemaskini sistem atau pangkalan data.</p>
                                      </div>
                                    </div>
                                    <div 
                                      onClick={handleToggleMaintenance} 
                                      className={`w-16 h-8 rounded-full relative cursor-pointer transition-colors shadow-inner flex-shrink-0 ${isMaintenanceMode ? 'bg-amber-500' : 'bg-slate-300'}`}
                                    >
                                      <div className={`w-6 h-6 bg-white rounded-full absolute top-1 shadow-sm transition-all duration-300 flex items-center justify-center ${isMaintenanceMode ? 'left-9' : 'left-1'}`}></div>
                                    </div>
                                </div>
                            </div>
                        </section>

                        <section>
                            <h4 className="text-[10px] font-black text-slate-400 uppercase tracking-widest mb-4">Security Settings</h4>
                            <form onSubmit={handleChangePassword} className="bg-white p-6 sm:p-8 rounded-3xl border border-slate-200 shadow-sm space-y-6">
                                <div className="flex items-center gap-3 mb-4">
                                    <div className="w-12 h-12 bg-emerald-50 rounded-2xl flex items-center justify-center text-emerald-50 flex-shrink-0 text-emerald-500"><Lock size={24} /></div>
                                    <div>
                                      <h3 className="text-lg font-black text-slate-800">Change Admin Password</h3>
                                      <p className="text-xs font-bold text-slate-400">Keep your master account secure</p>
                                    </div>
                                </div>
                                <div className="space-y-2">
                                    <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Current Password</label>
                                    <input type="password" required value={pwdData.old} onChange={e => setPwdData({...pwdData, old: e.target.value})} className="w-full p-4 bg-slate-50 border-2 border-slate-50 rounded-2xl outline-none focus:border-emerald-500 font-bold transition-colors text-sm text-slate-800" />
                                </div>
                                <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                                    <div className="space-y-2">
                                        <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">New Password</label>
                                        <input type="password" required value={pwdData.new} onChange={e => setPwdData({...pwdData, new: e.target.value})} className="w-full p-4 bg-slate-50 border-2 border-slate-50 rounded-2xl outline-none focus:border-emerald-500 font-bold transition-colors text-sm text-slate-800" />
                                    </div>
                                    <div className="space-y-2">
                                        <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest ml-1">Confirm New Password</label>
                                        <input type="password" required value={pwdData.confirm} onChange={e => setPwdData({...pwdData, confirm: e.target.value})} className="w-full p-4 bg-slate-50 border-2 border-slate-50 rounded-2xl outline-none focus:border-emerald-500 font-bold transition-colors text-sm text-slate-800" />
                                    </div>
                                </div>
                                <button disabled={isUpdatingPwd} type="submit" className="w-full sm:w-auto px-10 py-4 bg-slate-900 text-white rounded-2xl font-black uppercase tracking-widest text-[10px] hover:bg-emerald-600 transition-all flex items-center justify-center gap-2 shadow-lg shadow-slate-200 active:scale-95">
                                    {isUpdatingPwd ? <Loader2 className="animate-spin" size={16} /> : <Save size={16} />} 
                                    Update Password
                                </button>
                            </form>
                        </section>
                    </div>
                 </div>
              </div>
            )}
        </div>
      </main>
    </div>
  );
};

/* ============================================================================
   USER PORTAL (CLIENT)
   ============================================================================ */
const UserPortal = ({ currentUser, token, onLogout, onUpdateUser, packageSettings }) => {
  const [activeTab, setActiveTab] = useState('dashboard');
  const [credits, setCredits] = useState(currentUser.kredit || 0);

  // States
  const [isDeviceLinked, setIsDeviceLinked] = useState(false);
  const [qrStatus, setQrStatus] = useState('idle'); 
  const [qr, setQr] = useState(null);
  const isRequesting = useRef(false);

  const [isBlasting, setIsBlasting] = useState(false);
  const [blastProgress, setBlastProgress] = useState(0);
  const [messagesSent, setMessagesSent] = useState(0);
  const [messagesFailed, setMessagesFailed] = useState(0);
  const [message, setMessage] = useState('');
  const [targetSource, setTargetSource] = useState('manual');
  const [manualNumbers, setManualNumbers] = useState('');
  const [selectedGroup, setSelectedGroup] = useState('all');
  const [messageFormat, setMessageFormat] = useState('text'); 
  const [delayTime, setDelayTime] = useState(2); 
  const [campaigns, setCampaigns] = useState([]);
  const [mediaFile, setMediaFile] = useState(null);

  const [contacts, setContacts] = useState([]);
  const [newContact, setNewContact] = useState({ nama: '', nombor_telefon: '', kumpulan: 'General' });
  const [isAddingContact, setIsAddingContact] = useState(false);
  const [isUploadingCSV, setIsUploadingCSV] = useState(false); 
  const [isDeletingAll, setIsDeletingAll] = useState(false);
  const [searchContactQuery, setSearchContactQuery] = useState('');

  const [pwdData, setPwdData] = useState({ old: '', new: '', confirm: '' });
  const [isUpdatingPwd, setIsUpdatingPwd] = useState(false);
  const [profileData, setProfileData] = useState({ nama_syarikat: currentUser.nama_syarikat || '', profilePic: currentUser.profilePic || null });
  const [isUpdatingProfile, setIsUpdatingProfile] = useState(false);

  const [voucherCode, setVoucherCode] = useState('');
  const [isRedeeming, setIsRedeeming] = useState(false);
  const [notification, setNotification] = useState({ show: false, title: '', message: '', type: 'info' });
  const [blastResultModal, setBlastResultModal] = useState({ isOpen: false, success: 0, failed: 0 });

  // 🌍 STATE MAINTENANCE UNTUK CLIENT
  const [isSystemUnderMaintenance, setIsSystemUnderMaintenance] = useState(false);

  const currentPlan = currentUser.status_langganan || 'free';
  const isExpired = currentUser.expiryDate ? new Date() > new Date(currentUser.expiryDate) : false;
  const isFreePlan = currentPlan === 'free';
  const currentPlanSettings = packageSettings[currentPlan] || DEFAULT_PACKAGE_SETTINGS[currentPlan];
  const canUseImage = currentPlanSettings.allowImage;
  const canUseVideo = currentPlanSettings.allowVideo;
  const minDelayAllowed = isFreePlan ? 5 : 2; 

  const uniqueGroups = useMemo(() => Array.from(new Set(contacts.map(c => c.kumpulan))), [contacts]);
  const displayedContacts = useMemo(() => {
    if (!searchContactQuery) return contacts;
    const lowerQuery = searchContactQuery.toLowerCase();
    return contacts.filter(contact => contact.nama.toLowerCase().includes(lowerQuery) || contact.nombor_telefon.includes(lowerQuery) || contact.kumpulan.toLowerCase().includes(lowerQuery));
  }, [contacts, searchContactQuery]);

  const showNotification = (title, message, type = 'info') => { setNotification({ show: true, title, message, type }); };

  const fetchData = async () => {
    try {
      const userId = currentUser.id || currentUser._id;
      const [contactRes, campaignRes] = await Promise.all([
        fetch(`${API_URL}/contacts/${userId}`), fetch(`${API_URL}/campaigns/${userId}`)
      ]);
      if (contactRes.ok) setContacts(await contactRes.json());
      if (campaignRes.ok) setCampaigns(await campaignRes.json());
    } catch (err) {}
  };

  // Check Maintenance Polling (Setiap 60 saat)
  useEffect(() => {
    const checkMaintenance = async () => {
       try {
         const res = await fetch(`${API_URL}/system/status`);
         if(res.ok) {
            const data = await res.json();
            setIsSystemUnderMaintenance(data.maintenance);
         }
       } catch(e){}
    };
    checkMaintenance();
    const interval = setInterval(checkMaintenance, 60000);
    return () => clearInterval(interval);
  }, []);

  useEffect(() => {
    if(!isSystemUnderMaintenance) {
      fetchData();
      setCredits(currentUser.kredit || 0);
      if(delayTime < minDelayAllowed) setDelayTime(minDelayAllowed);
    }
    // eslint-disable-next-line
  }, [activeTab, currentUser, minDelayAllowed, isSystemUnderMaintenance]);

  const handleAddContact = async (e) => {
    e.preventDefault();
    if (!newContact.nombor_telefon) return;
    setIsAddingContact(true);
    try {
      const res = await fetch(`${API_URL}/contacts`, {
        method: 'POST', headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ user_id: currentUser.id || currentUser._id, ...newContact })
      });
      if (res.ok) {
        setNewContact({ nama: '', nombor_telefon: '', kumpulan: 'General' });
        fetchData(); showNotification("Success", "New contact has been saved.", "success");
      }
    } catch (err) { showNotification("Error", "Failed to save contact.", "error"); } 
    finally { setIsAddingContact(false); }
  };

  const handleDeleteContact = async (id) => {
    if (!window.confirm("Are you sure you want to delete this contact?")) return;
    try {
      const res = await fetch(`${API_URL}/contacts/${id}`, { method: 'DELETE' });
      if (res.ok) fetchData();
    } catch (err) {}
  };

  const handleDeleteAllContacts = async () => {
    if (!window.confirm("WARNING! Are you sure you want to delete ALL contacts?")) return;
    setIsDeletingAll(true);
    try {
      await Promise.all(contacts.map(contact => fetch(`${API_URL}/contacts/${contact._id}`, { method: 'DELETE' })));
      showNotification("Completed", "All contacts deleted!", "success"); fetchData();
    } catch (err) { showNotification("Error", "An error occurred.", "error"); } 
    finally { setIsDeletingAll(false); }
  };

  const handleFormatChange = (format) => {
    if (format === 'image' && !canUseImage) return showNotification("Akses Dihadkan", "Penghantaran gambar tidak dibenarkan dalam pakej anda.", "warning");
    if (format === 'video' && !canUseVideo) return showNotification("Akses Dihadkan", "Penghantaran video tidak dibenarkan dalam pakej anda.", "warning");
    setMessageFormat(format); setMediaFile(null); 
  };

  const handleMediaUpload = (e) => {
    const file = e.target.files[0];
    if (!file) return;
    if (file.size > 16 * 1024 * 1024) {
      showNotification("File Too Large", "Maximum file size is 16MB.", "warning");
      e.target.value = null; return;
    }
    const reader = new FileReader();
    reader.onload = (event) => { setMediaFile({ file: file, type: file.type, name: file.name, base64: event.target.result }); };
    reader.readAsDataURL(file); e.target.value = null; 
  };

  const handleFileUpload = async (e) => {
    const file = e.target.files[0];
    if (!file) return;
    setIsUploadingCSV(true);
    try {
      const XLSX = await new Promise((resolve, reject) => {
        if (window.XLSX) return resolve(window.XLSX);
        const script = document.createElement('script');
        script.src = "https://cdnjs.cloudflare.com/ajax/libs/xlsx/0.18.5/xlsx.full.min.js";
        script.onload = () => resolve(window.XLSX);
        script.onerror = () => reject(new Error('Failed to load XLSX'));
        document.head.appendChild(script);
      });

      const reader = new FileReader();
      reader.onload = async (event) => {
        try {
          const data = new Uint8Array(event.target.result);
          const workbook = XLSX.read(data, { type: 'array' });
          const rows = XLSX.utils.sheet_to_json(workbook.Sheets[workbook.SheetNames[0]], { header: 1 });
          const newContacts = [];

          for (let i = 0; i < rows.length; i++) {
            const row = rows[i];
            if (!row || row.length === 0) continue;
            let col0 = row[0] !== undefined ? String(row[0]).trim() : ''; let col1 = row[1] !== undefined ? String(row[1]).trim() : ''; let col2 = row[2] !== undefined ? String(row[2]).trim() : '';
            if (col0 && !col1 && col0.includes(',')) {
                const splitCols = col0.split(/[,;\t]/);
                col0 = splitCols[0] ? splitCols[0].replace(/"/g, '').trim() : ''; col1 = splitCols[1] ? splitCols[1].replace(/"/g, '').trim() : ''; col2 = splitCols[2] ? splitCols[2].replace(/"/g, '').trim() : '';
            }
            let nama = col0; let nombor = col1; let kumpulan = col2;
            if (!nombor && nama) { const possibleNumber = nama.replace(/[^0-9]/g, ''); if (possibleNumber.length > 8) { nombor = possibleNumber; nama = 'Customer'; } }
            if (i === 0 && (nama.toLowerCase().includes('name') || nama.toLowerCase().includes('nama') || (nombor && nombor.toLowerCase().includes('number')))) continue;

            const cleanPhone = nombor ? nombor.replace(/[^0-9]/g, '') : '';
            if (!cleanPhone || cleanPhone.length < 8) continue; 
            newContacts.push({ nama: nama || 'Customer', nombor_telefon: cleanPhone, kumpulan: kumpulan || 'Excel/CSV Import' });
          }

          if (newContacts.length === 0) { showNotification("Invalid Format", "No valid data found.", "warning"); setIsUploadingCSV(false); return; }
          const res = await fetch(`${API_URL}/contacts/bulk`, { method: 'POST', headers: { 'Content-Type': 'application/json' }, body: JSON.stringify({ user_id: currentUser.id || currentUser._id, contacts: newContacts }) });
          if (res.ok) { showNotification("Import Successful", `${newContacts.length} contacts saved!`, "success"); fetchData(); }
        } catch (err) { showNotification("File Error", "Failed to process file.", "error"); } finally { setIsUploadingCSV(false); if (e.target) e.target.value = null; }
      };
      reader.readAsArrayBuffer(file);
    } catch (err) { showNotification("Error", "Failed to load Excel engine.", "error"); setIsUploadingCSV(false); }
  };

  const connectWA = async () => {
    setQrStatus('loading'); setQr(null);
    try { await fetch(`${API_URL}/whatsapp/connect/${currentUser.id || currentUser._id}`); } 
    catch (err) { setQrStatus('error'); }
  };

  const logoutWA = async () => {
    setQrStatus('disconnecting');
    try { await fetch(`${API_URL}/whatsapp/logout`, { method: 'POST', headers: { 'Content-Type': 'application/json' }, body: JSON.stringify({ userId: currentUser.id || currentUser._id }) }); } catch (err) {}
    setQrStatus('idle'); setIsDeviceLinked(false); setQr(null);
  };

  useEffect(() => {
    if(isSystemUnderMaintenance) return;
    let interval; let isMounted = true;
    const userId = currentUser.id || currentUser._id;
    const checkServerStatus = async () => {
      if (isRequesting.current) return; 
      isRequesting.current = true;
      try {
        const res = await fetch(`${API_URL}/whatsapp/connect/${userId}`);
        const data = await res.json();
        if (!isMounted) return;
        if (data.status === 'connected' || data.connected) { setQrStatus('connected'); setIsDeviceLinked(true); setQr(null); } 
        else if (data.status === 'disconnected') { setQrStatus('idle'); setIsDeviceLinked(false); setQr(null); } 
        else if (data.qr && qrStatus !== 'connected') { setQr(prevQr => prevQr !== data.qr ? data.qr : prevQr); setQrStatus('qr_ready'); }
      } catch (err) {} finally { isRequesting.current = false; }
    };

    if (qrStatus === 'loading' || qrStatus === 'qr_ready') { interval = setInterval(checkServerStatus, 1500); } 
    else if (qrStatus === 'connected') { interval = setInterval(checkServerStatus, 5000); }
    return () => { isMounted = false; if (interval) clearInterval(interval); };
  }, [qrStatus, currentUser, isSystemUnderMaintenance]);

  const startBlast = async () => {
    if (currentUser.isCreditLocked) return showNotification("Action Denied", "Kredit anda telah dikunci. Sila hubungi Admin.", "error");
    if (isExpired) return showNotification("Subscription Expired", "Sila perbaharui pelan anda untuk menghantar mesej.", "error");
    if (delayTime < minDelayAllowed) return showNotification("Warning", `Minimum delay for your plan is ${minDelayAllowed} seconds.`, "warning");
    if (!isDeviceLinked) { showNotification("Session Inactive", "Please connect your WhatsApp first.", "warning"); setActiveTab('dashboard'); return; }

    let numbers = [];
    if (targetSource === 'manual') numbers = manualNumbers.split(/[\n,]+/).map(n => n.trim()).filter(n => n.length > 5);
    else {
      const filteredContacts = selectedGroup === 'all' ? contacts : contacts.filter(c => c.kumpulan === selectedGroup);
      numbers = filteredContacts.map(c => c.nombor_telefon);
    }

    if (numbers.length === 0) return showNotification("No Target", "Please add target numbers.", "warning");
    if (messageFormat !== 'text' && !mediaFile) return showNotification("File Required", "Please upload media.", "warning");
    if (messageFormat === 'text' && !message) return showNotification("Empty Message", "Please type a message.", "warning");
    if (credits < numbers.length) return showNotification("Insufficient Credits", `You need ${numbers.length} credits.`, "error");

    setIsBlasting(true); setBlastProgress(0); setMessagesSent(0); setMessagesFailed(0);
    let successCount = 0; let failCount = 0;

    for (let i = 0; i < numbers.length; i++) {
      try {
        let targetNumber = numbers[i].replace(/[^0-9]/g, ''); 
        if (targetNumber.startsWith('0')) targetNumber = '6' + targetNumber; else if (targetNumber.startsWith('+')) targetNumber = targetNumber.substring(1);
        const payload = { userId: currentUser.id || currentUser._id, to: targetNumber, message };
        if (messageFormat !== 'text' && mediaFile) { payload.media = mediaFile.base64.split(',')[1]; payload.mediaType = mediaFile.type; payload.fileName = mediaFile.name; }

        const res = await fetch(`${API_URL}/whatsapp/send`, { method: 'POST', headers: { 'Content-Type': 'application/json' }, body: JSON.stringify(payload) });
        if (res.ok) { successCount++; setMessagesSent(successCount); setCredits(prev => prev - 1); } 
        else { failCount++; setMessagesFailed(failCount); }
      } catch (err) { failCount++; setMessagesFailed(failCount); }
      setBlastProgress(Math.floor(((i + 1) / numbers.length) * 100));
      await new Promise(resolve => setTimeout(resolve, delayTime * 1000)); 
    }

    try {
      await fetch(`${API_URL}/campaigns`, {
        method: 'POST', headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ user_id: currentUser.id || currentUser._id, nama_kempen: `Blast Campaign - ${new Date().toLocaleDateString()}`, mesej: message || 'Media Campaign', jumlah_sasaran: numbers.length, jumlah_berjaya: successCount, jumlah_gagal: failCount, status: 'completed' })
      });
    } catch(err) {}

    setTimeout(() => { setIsBlasting(false); setBlastResultModal({ isOpen: true, success: successCount, failed: failCount }); }, 1500);
  };

  const handlePurchasePackage = (pkg, type = 'topup') => {
    const adminPhone = "60169012445"; 
    let text = type === 'subscription' 
      ? `Hi AR Connect Admin,\n\nI am ${currentUser.nama_syarikat} (${currentUser.email}) and I am interested in subscribing to:\n\n📅 *Plan: ${pkg.name}*\n💎 *Quota: ${pkg.credits.toLocaleString()} Credits/month*\n💰 *Price: RM${pkg.price}/month*`
      : `Hi AR Connect Admin,\n\nI am ${currentUser.nama_syarikat} (${currentUser.email}) and I am interested in purchasing a Topup:\n\n📦 *Package: ${pkg.label}*\n💎 *Amount: ${pkg.amount.toLocaleString()} Credits ${pkg.bonus ? `(${pkg.bonus})` : ''}*\n💰 *Price: RM${pkg.price}*`;
    window.open(`https://wa.me/${adminPhone}?text=${encodeURIComponent(text)}`, '_blank');
  };

  const handleRedeemVoucher = async () => {
    if (!voucherCode.trim()) return showNotification("Gagal", "Sila masukkan Kod Voucher atau PIN Topup terlebih dahulu.", "warning");
    setIsRedeeming(true);
    try {
       const res = await fetch(`${API_URL}/vouchers/redeem`, {
          method: 'POST', headers: { 'Content-Type': 'application/json', 'Authorization': `Bearer ${token}` },
          body: JSON.stringify({ userId: currentUser.id || currentUser._id, code: voucherCode.toUpperCase() })
       });
       const data = await res.json();
       if (res.ok) {
          setCredits(prev => prev + data.amount);
          const updatedUser = { ...currentUser, kredit: (currentUser.kredit || 0) + data.amount };
          localStorage.setItem('user', JSON.stringify(updatedUser)); onUpdateUser(updatedUser);
          showNotification("Berjaya!", `Tahniah! ${data.amount} Kredit telah dimasukkan ke akaun anda secara automatik.`, "success"); setVoucherCode('');
       } else { showNotification("Tidak Sah", data.message || "Kod tidak sah atau telah digunakan.", "error"); }
    } catch(err) { showNotification("Ralat", "Pelayan sistem sedang sibuk, sila cuba sebentar lagi.", "error"); }
    setIsRedeeming(false);
  };

  const handleChangePassword = async (e) => {
    e.preventDefault();
    if (pwdData.new !== pwdData.confirm) return showNotification("Error", "New passwords do not match.", "error");
    setIsUpdatingPwd(true);
    try {
      const res = await fetch(`${API_URL}/auth/change-password`, {
        method: 'POST', headers: { 'Content-Type': 'application/json', 'Authorization': `Bearer ${token}` },
        body: JSON.stringify({ userId: currentUser.id || currentUser._id, old: pwdData.old, new: pwdData.new })
      });
      if (res.ok) { showNotification("Success", "Password updated successfully.", "success"); setPwdData({ old: '', new: '', confirm: '' }); } 
      else { const data = await res.json(); showNotification("Error", data.message || "Failed to update password.", "error"); }
    } catch (err) { showNotification("Error", "Server connection error.", "error"); } finally { setIsUpdatingPwd(false); }
  };

  const handleProfilePicChange = (e) => {
    const file = e.target.files[0];
    if (file) {
      if (file.size > 2 * 1024 * 1024) return showNotification("File Too Large", "Profile picture must be under 2MB.", "warning");
      const reader = new FileReader();
      reader.onload = (event) => { setProfileData({ ...profileData, profilePic: event.target.result }); };
      reader.readAsDataURL(file);
    }
  };

  const handleUpdateProfile = async (e) => {
    e.preventDefault();
    setIsUpdatingProfile(true);
    try {
      const res = await fetch(`${API_URL}/auth/update-profile`, {
        method: 'POST', headers: { 'Content-Type': 'application/json', 'Authorization': `Bearer ${token}` },
        body: JSON.stringify({ nama_syarikat: profileData.nama_syarikat, profilePic: profileData.profilePic })
      });
      if (res.ok) {
        const data = await res.json();
        const updatedUser = { ...currentUser, nama_syarikat: data.user.nama_syarikat, profilePic: data.user.profilePic };
        localStorage.setItem('user', JSON.stringify(updatedUser)); onUpdateUser(updatedUser); showNotification("Success", "Profile saved to database successfully.", "success");
      } else { const errorData = await res.json(); showNotification("Error", errorData.message || "Failed to save profile.", "error"); }
    } catch (err) { showNotification("Error", "Server connection error.", "error"); } finally { setIsUpdatingProfile(false); }
  };

  // --- UI JIKA AKAUN DIGANTUNG ---
  if (currentUser.isSuspended) {
    return (
      <div className="h-screen w-full flex items-center justify-center bg-slate-900 text-white p-6 font-sans">
        <div className="text-center space-y-6 max-w-md animate-in zoom-in duration-500">
           <div className="w-24 h-24 bg-red-500/20 rounded-full flex items-center justify-center mx-auto mb-4 border border-red-500/30 shadow-[0_0_40px_rgba(239,68,68,0.3)]"><Ban size={48} className="text-red-500" /></div>
           <div><h1 className="text-3xl font-black mb-2">Akaun Digantung</h1><p className="text-slate-400 text-sm leading-relaxed">Akses ke AR Connect telah disekat untuk akaun ini kerana masalah polisi atau pembayaran. Sila hubungi Admin kami untuk bantuan.</p></div>
